import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('brain-pop');

  useEffect(() => {
    const timer1 = setTimeout(() => setStage('cc-draw'), 1500);
    const timer2 = setTimeout(() => setStage('main'), 3500);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
    { title: 'Update Acknowledger', desc: 'Stay updated.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* DEBUG TEXT (you can remove later) */}
      <p style={{ position: 'fixed', top: 10, left: 10, color: 'red', zIndex: 9999 }}>
        STAGE: {stage}
      </p>

      {/* INTRO ANIMATIONS */}
      <AnimatePresence mode="wait">
        {stage === 'brain-pop' && (
          <motion.div
            key="brain-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0, scale: 1.1 }}
          >
            <motion.img
              src="/logo.jpeg"
              alt="Logo Pop"
              className="w-64 h-64 object-contain"
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: [1, 1.1, 1], opacity: 1 }}
              transition={{ duration: 1 }}
            />
          </motion.div>
        )}

        {stage === 'cc-draw' && (
          <motion.div
            key="cc-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0 }}
          >
            <svg width="400" height="200" viewBox="0 0 200 100">
              <motion.path
                d="M60 30 C 20 30, 20 70, 60 70"
                fill="none"
                stroke="#0B3954"
                strokeWidth="8"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1 }}
              />
              <motion.path
                d="M140 30 C 100 30, 100 70, 140 70"
                fill="none"
                stroke="#0B3954"
                strokeWidth="8"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1, delay: 0.2 }}
              />
            </svg>
          </motion.div>
        )}
      </AnimatePresence>

      {/* MAIN CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>

          {/* HEADER */}
          <header className="fixed top-0 left-0 right-0 h-48 flex items-center justify-between px-10 z-40 bg-white/40 backdrop-blur-2xl">
            <div className="flex items-center -ml-12 mt-2">
              <img
                src="/logo.jpeg"
                alt="CourseCraft"
                className="h-56 w-auto object-contain"
              />
            </div>

            <div className="flex items-center space-x-10">
              <button className="text-sm font-bold tracking-[0.3em] text-[#0B3954]">
                LOG IN
              </button>
              <button className="px-12 py-5 bg-[#0B3954] text-white rounded-full text-xs font-bold tracking-[0.3em]">
                SIGN UP
              </button>
            </div>
          </header>

          {/* HERO */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <h1 className="text-7xl md:text-[11rem] leading-none text-black">
              Welcome to <br />
              <span className="italic font-light text-[#0B3954]">
                CourseCraft
              </span>
            </h1>
          </section>

          {/* FEATURES */}
          <section className="py-40 bg-[#0B3954] text-white overflow-hidden">

            <div className="flex mb-12">
              <motion.div
                className="flex space-x-10 px-4"
                animate={{ x: [0, -1200] }}
                transition={{ duration: 25, repeat: Infinity, ease: "linear" }}
              >
                {featuresRow1.map((f, i) => (
                  <div key={i} className="min-w-[500px] p-10 bg-white/10 rounded-3xl">
                    <h3>{f.title}</h3>
                    <p>{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>

          </section>

          <footer className="h-64 flex items-center justify-center">
            <p>© 2026 CourseCraft</p>
          </footer>

        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
